import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const AssignedSystems = () => {
  const navigate = useNavigate();

  const systemsData = [
    {
      systemId: "SYS-10234",
      owner: "Finance Dept",
      assignedDate: "2026-01-12",
      severity: "Critical",
      rootCause: "Disk I/O saturation",
      status: "In Progress",
      slaHours: -2,
      category: "Hardware",
    },
    {
      systemId: "SYS-10241",
      owner: "HR Systems",
      assignedDate: "2026-01-14",
      severity: "High",
      rootCause: "Authentication service failure",
      status: "Pending",
      slaHours: 5,
      category: "Security",
    },
    {
      systemId: "SYS-10258",
      owner: "Manufacturing",
      assignedDate: "2026-01-15",
      severity: "Medium",
      rootCause: "Memory leak in service",
      status: "Awaiting Evidence",
      slaHours: 18,
      category: "Software",
    },
  ];

  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("All");

  const openDiagnosis = (systemId) => {
    navigate(`/technician/system-diagnosis/${systemId}`);
  };

  const severityStyles = {
    Critical: "bg-red-100 text-red-700",
    High: "bg-orange-100 text-orange-700",
    Medium: "bg-yellow-100 text-yellow-700",
  };

  const statusStyles = {
    Pending: "bg-gray-100 text-gray-700",
    "In Progress": "bg-blue-100 text-blue-700",
    "Awaiting Evidence": "bg-purple-100 text-purple-700",
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-semibold">Assigned Systems</h1>
          <p className="text-sm text-gray-500">
            Systems assigned to you for investigation
          </p>
        </div>

        <input
          placeholder="Search System ID or Owner"
          className="border rounded px-3 py-2 text-sm"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="bg-white border rounded-lg overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-3 text-left">System ID</th>
              <th className="px-4 py-3 text-left">Owner</th>
              <th className="px-4 py-3">Severity</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3">SLA</th>
              <th className="px-4 py-3">Action</th>
            </tr>
          </thead>

          <tbody>
            {systemsData.map((sys) => (
              <tr
                key={sys.systemId}
                className={`border-t ${
                  sys.severity === "Critical" ? "bg-red-50" : ""
                }`}
              >
                <td className="px-4 py-3 font-medium text-blue-600">
                  {sys.systemId}
                </td>
                <td className="px-4 py-3">{sys.owner}</td>

                <td className="px-4 py-3 text-center">
                  <span
                    className={`px-2 py-1 rounded-full text-xs ${severityStyles[sys.severity]}`}
                  >
                    {sys.severity}
                  </span>
                </td>

                <td className="px-4 py-3 text-center">
                  <span
                    className={`px-2 py-1 rounded-full text-xs ${statusStyles[sys.status]}`}
                  >
                    {sys.status}
                  </span>
                </td>

                <td className="px-4 py-3 text-center font-medium text-red-600">
                  {sys.slaHours < 0 ? "BREACHED" : `${sys.slaHours} hrs`}
                </td>

                <td className="px-4 py-3 text-center">
                  <button
                    onClick={() => openDiagnosis(sys.systemId)}
                    className="text-blue-600 hover:underline"
                  >
                    Open Diagnosis
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AssignedSystems;
